package postgres

import (
	"context"
	"errors"
	"fmt"
	"time"

	"github.com/jackc/pgx/v5"

	"github.com/gotha/luna-podcatcher/internal/transcribe"
)

// TranscriptStore adapts the shared postgres Store to transcribe.Store. It is a
// thin wrapper (no new state) so a single pgx pool/owner serves every domain; it
// exists because transcribe.Store and download.Store both declare an ItemByID
// method with different return types, which one Go type cannot provide.
type TranscriptStore struct {
	*Store
}

// NewTranscriptStore returns a transcribe.Store backed by s.
func NewTranscriptStore(s *Store) *TranscriptStore { return &TranscriptStore{Store: s} }

// transcriptItemColumns is the transcribe-view column list: the item id/feed plus
// its downloaded file path and download time (from the download record).
const transcriptItemColumns = `fi.id::text, fi.feed_id::text, COALESCE(d.file_path, ''), d.downloaded_at`

// ItemsForTranscription implements transcribe.Store: active-feed items that are
// downloaded and have no transcript or whose audio was re-downloaded since the
// last transcript (change detected via the download's downloaded_at).
func (ts *TranscriptStore) ItemsForTranscription(ctx context.Context) ([]transcribe.Item, error) {
	const q = `
SELECT ` + transcriptItemColumns + `
FROM feed_items fi
JOIN feeds f ON f.id = fi.feed_id AND f.status = 'active'
JOIN feed_item_downloads d ON d.feed_item_id = fi.id AND d.status = 'downloaded'
LEFT JOIN feed_item_transcripts t ON t.feed_item_id = fi.id AND t.status = 'transcribed'
WHERE t.feed_item_id IS NULL
   OR t.source_downloaded_at IS DISTINCT FROM d.downloaded_at
ORDER BY fi.published_at NULLS LAST, fi.id`

	rows, err := ts.pool.Query(ctx, q)
	if err != nil {
		return nil, fmt.Errorf("list items for transcription: %w", err)
	}
	defer rows.Close()

	var out []transcribe.Item
	for rows.Next() {
		it, err := scanTranscriptItem(rows)
		if err != nil {
			return nil, fmt.Errorf("scan item: %w", err)
		}
		out = append(out, it)
	}
	if err := rows.Err(); err != nil {
		return nil, fmt.Errorf("iterate items: %w", err)
	}
	return out, nil
}

// ItemByID implements transcribe.Store: the item with its downloaded audio path
// and download time, regardless of feed status. An unknown id yields ErrNotFound;
// an item with no downloaded audio yields ErrNotDownloaded.
func (ts *TranscriptStore) ItemByID(ctx context.Context, id string) (transcribe.Item, error) {
	const q = `
SELECT ` + transcriptItemColumns + `
FROM feed_items fi
LEFT JOIN feed_item_downloads d ON d.feed_item_id = fi.id AND d.status = 'downloaded'

-- Telescope fuzzy finder
{
	"nvim-telescope/telescope.nvim",
	branch = "0.1.x",
	dependencies = { "nvim-lua/plenary.nvim" },
	keys = {
		{ "<leader>tf", "<cmd>Telescope find_files<cr>", desc = "Find Files" },
		{ "<leader>tg", "<cmd>Telescope live_grep<cr>", desc = "Live Grep" },
		{ "<leader>tb", "<cmd>Telescope buffers<cr>", desc = "Buffers" },
		{ "<leader>th", "<cmd>Telescope help_tags<cr>", desc = "Help Tags" },
		{ "<leader>tr", "<cmd>Telescope resume<cr>", desc = "Resume" },
	},
	config = function()
		require("plugins/telescope")
	end,
},

